e_view_app_0 {      background-color: #ffebeb;    }    .active_view_app_0 + ul .div{      background-color: #ffebeb;    }    .pull-auto {	    margin: auto;    }</style><style>    .tab-btn {        flex: 1;        padding: 15px 20px;        border: none;        background: transparent;        cursor: pointer;        border-radius: 10px;        font-weight: 600;        transition: all 0.3s ease;        color: #6c757d;    }    .tab-btn.active {        /*background: #3a94ef;*/        color: white;        /*box-shadow: 0 5px 15px rgba(79, 172, 254, 0.3);*/        margin-right: 5px;        border: 1;    }    .nav.nav-tabs > li.tab-btn.active > a {        background-color: #3a94ef;        color: white !important;        border: 0;        border-radius: 10px;    }    .tab-btn:hover:not(.active) {        background: rgba(79, 172, 254, 0.1);        color: #4facfe;    }    .content_auto + .mleft10 {        display: none!important;    }    .content_auto + .mleft10 + .onoffswitch.pull-auto {        display: none!important;    }</style><div class="card-box">    <div class="row">        <div class="col-sm-12">            <h4 class="page-title text-capitalize">{{$title ?? ''}} - <a title="{{lang('edit_c_script_content')}}" class="dt-modal" href="admin/script/detail_content/{{$dtScriptDetail->id_script}}"><i class="fa fa-edit"></i></a></h4>        </div>    </div>    <div class="row">        <div class="col-md-12">            <div class="table-responsive">                <div class="tree">                    <ul class="ul_0">                        <li>                            <div class="div div_child_{{!empty($dtScriptDetail->id) ?? NULL}} {{!empty($dtScriptDetail->use_limit) ? 'bg-danger' : ''}}">                                <div>                                    <span class="content_auto">                                        {{$dtScriptDetail->name}} ({{list_event_show($dtScriptDetail->event_show)}}) - {!! empty($dtScriptDetail->type_send) ? '<b class="text-warning">(Nhân viên)</b>' : '<b class="text-success">'.($dtScriptDetail->type_send == 2 ? 'Tiêu đề' : 'Khách hàng').'</b>' !!}                                    </span>                                    <span class="mleft10">                                        <a class="dt-modal" href="{{'admin/script/edit_detail_child/' . $dtScriptDetail->id}}">                                            <i class="fa fa-edit"></i>                                        </a>                                    </span>                                    <div class="onoffswitch pull-auto">                                        <input type="checkbox" data-id="{{$dtScriptDetail->id}}"                                               class="onoffswitch-checkbox checkStatus"                                               id="c_active_{{$dtScriptDetail->id}}" {{!empty($dtScriptDetail->active_view_app) ? 'checked' : ''}}>                                        <label class="onoffswitch-label" for="c_active_{{$dtScriptDetail->id}}"></label>                                    </div>                                    <div><i class="div_content">{{lang('content_send')}}: {{$dtScriptDetail->content}}</i></div>                                    <div><i class="div_file"></i></div>                                </div>                                <div class="mtop10">                                    <a onclick="plusChild(this, {{$dtScriptDetail->id}})"><i class="fa fa-plus"></i></a>                                </div>                            </div>                            {!!getViewChildScript($dtScriptDetail->id)!!}                        </li>                    </ul>                </div>            </div>        </div>    </div></div><div class="clearfix"></div>@endsection@section('script')<script>   function plusChild(_this, id_parent = ''){       $.ajax({           type: "POST",           url: 'admin/script/add_detail_parent',           data: {               id_parent : id_parent           },           dataType: "json",           success: function (result) {               alert_float(result.alert_type, result.message)               if(result.result) {                   if($(`ul.ul_${id_parent}`).length == 0) {                       $($(_this).parents('.div').parent('li').append(`<ul class="ul_${id_parent}"></ul>`));                   }                   $(`.ul_${id_parent}`).append(`<li><div class="div div_child_${result.id} active_view_app_${result.active_view_app}">${result.html}</div></li>`);               }           }       });    }    function removeBotChat(id_script_detail = '') {        if(!confirm('Bạn có chắc muốn xóa, Dữ liệu xóa không thể khôi phục!')) {            return false;        }        $.ajax({            type: "POST",            url: 'admin/script/delete_script_detail',            data: {                id : id_script_detail            },            dataType: "json",            success: function (result) {                alert_float(result.alert_type, result.message);                if(result.success) {                    $('.div_child_' + id_script_detail).parent('li').remove();                    if($(`.ul_${result.id_parent}`).find('li').length == 0) {                        $(`.ul_${result.id_parent}`).remove();                    }                }            }        });    }    $(function() {        scrollTree();    })    function scrollTree() {        var maxLi = 0;        var ulTree = $('.tree').find('ul');        $.each(ulTree, function(index, value) {            var data_px = 0;            var countLi = $(value).find('> li');            $.each(countLi, function(i, v) {                data_px += $(v).width();            })            if(data_px > maxLi) {                maxLi = data_px;            }        })        if(maxLi < 8) {            maxLi = 8;        }        // $('.tree').css('width', ((maxLi + 1) * 200) + 'px');        if(maxLi == 0) {            $('.tree').css('width', '');        }        else {            $('.tree').css('width', maxLi + 300 + 'px');        }    }   $('.tree').mousemove(function(){       scrollTree();   });   $('body').on('change', '.checkStatus', function() {        var id = $(this).data('id');        var active_view_app = $(this).prop('checked');        if(active_view_app == true) {            active_view_app = 1;        }        else {            active_view_app = 0;        }        var checkStatus = $(this);       $.ajax({           type: "POST",           url: 'admin/script/change_status_detail',           data: {               id : id,               active_view_app : active_view_app,           },           dataType: "json",           success: function (result) {               if(result.success) {                   if(active_view_app == 1) {                       $.each(result.list_id, function(index, value) {                           $(`#c_active_${value}`).attr('checked', true);                           $(`#c_active_${value}`).prop('checked', true);                       })                       checkStatus.parent('.onoffswitch').parent('.content_auto').parent('div').parent('.div').removeClass('active_view_app_0');                       checkStatus.parent('.onoffswitch').parent('.content_auto').parent('div').parent('.div').addClass('active_view_app_1');                   }                   else {                       $.each(result.list_id, function(index, value) {                           $(`#c_active_${value}`).attr('checked', false);                           $(`#c_active_${value}`).prop('checked', false);                       })                       checkStatus.parent('.onoffswitch').parent('.content_auto').parent('div').parent('.div').removeClass('active_view_app_1');                       checkStatus.parent('.onoffswitch').parent('.content_auto').parent('div').parent('.div').addClass('active_view_app_0');                   }               }               else {                   if(active_view_app == 1) {                       console.log($(`#c_active_${id}`))                       $(`#c_active_${id}`).prop('checked', false);                   }                   else {                       $(`#c_active_${id}`).prop('checked', true);                   }               }           }       });   })</script>@endsection